dashboard.definition:
{
  "title": "Leafs",
  "visualizations": {
    "viz_leafs_0": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_leafs_0"
      },
      "title": "NVE VNIs \u25b2 Up / \u25bc Down (Leaves)",
      "description": "Single card showing the latest-snapshot count of operationally Up (\u25b2) and Down (\u25bc) NVE VNIs (cisco.vni-oper-state_info, nve-vni-oper) aggregated across every leaf. A non-zero \u25bc Down count flags a VNI gone operationally down (e.g. an L3VNI core SVI shut).",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_leafs_1": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_leafs_1"
      },
      "title": "BGP Sessions \u25b2 Up / \u25bc Down (Leaves)",
      "description": "Single card showing the latest-snapshot count of BGP sessions that are Up (\u25b2, negotiated hold-time > 0) and Down (\u25bc, hold-time = 0) across every leaf. A non-zero \u25bc Down count flags one or more BGP neighbors not Established.",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_leafs_2": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_leafs_2"
      },
      "title": "VTEP Tunnel Peers (Leaves)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_leafs_3": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_leafs_3"
      },
      "title": "Active L2 VNIs (Leaves)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_leafs_4": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_leafs_4"
      },
      "title": "Active VRFs / L3 VNIs (Leaves)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_leafs_5": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_leafs_5"
      },
      "title": "Silent Leaves (>5m)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off",
        "backgroundColor": "> primary | seriesByIndex(0) | lastPoint() | rangeValue(singleValueColorConfig)"
      },
      "context": {
        "singleValueColorConfig": [
          {
            "to": 1,
            "value": "#53A051"
          },
          {
            "from": 1,
            "value": "#DC4E41"
          }
        ]
      }
    },
    "viz_leafs_6": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_6"
      },
      "title": "BGP Established Sessions per Leaf",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Sessions",
        "nullValueDisplay": "connect"
      }
    },
    "viz_leafs_7": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_7"
      },
      "title": "L3 VNI (VRF) Count per Leaf",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VNI Count",
        "nullValueDisplay": "connect"
      }
    },
    "viz_leafs_8": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_leafs_8"
      },
      "title": "BGP EVPN Peering Detail",
      "options": {
        "columnFormat": {
          "session_state": {
            "color": "> table | seriesByName(\"session_state\") | matchValue(sessionstateColorConfig)"
          }
        }
      },
      "context": {
        "sessionstateColorConfig": [
          {
            "match": "ESTABLISHED",
            "value": "#53A051"
          },
          {
            "match": "DOWN",
            "value": "#DC4E41"
          }
        ]
      }
    },
    "viz_leafs_9": {
      "type": "splunk.area",
      "dataSources": {
        "primary": "ds_leafs_9"
      },
      "title": "BGP Session Flaps \u2014 New Drops per Leaf Over Time",
      "description": "Per-interval delta of the cumulative connection.total-dropped counter (Sub 40114); the time bucket follows the selected time range. A non-zero spike marks a BGP session teardown/reset on that leaf.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "New Session Drops / interval",
        "nullValueDisplay": "zero",
        "stackMode": "stacked"
      }
    },
    "viz_leafs_10": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_10"
      },
      "title": "BGP Update Rate \u2014 Messages Received per Leaf",
      "description": "Per-minute delta of bgp-neighbor-counters.received.updates (Sub 40114). Sustained high rates indicate control-plane churn (route flap, MAC moves) on that leaf.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Update Messages / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_leafs_11": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_11"
      },
      "title": "BGP EVPN Table Version Churn \u2014 Route Changes/min per Leaf",
      "description": "Per-minute delta of the l2vpn-evpn bgp-table-version (Sub 40116). Each increment is a batch of EVPN route changes; sustained churn points to instability in the overlay.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Table Version Delta / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_leafs_12": {
      "type": "splunk.column",
      "dataSources": {
        "primary": "ds_leafs_12"
      },
      "title": "MAC & MAC/IP Route Churn per Leaf (Sub 40113 \u2014 requires IOS-XE 26.2.1+)",
      "description": "Per-minute delta of the cumulative Type-2 MAC + MAC/IP advertisement counters (local+remote) from evpn-vni-rt-cnt. Highlights host-mobility / MAC-move activity per leaf.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "MAC/MAC-IP Updates / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_leafs_13": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_13"
      },
      "title": "NVE Peers Over Time \u2014 Per Leaf",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VTEP Peers",
        "nullValueDisplay": "connect"
      }
    },
    "viz_leafs_14": {
      "type": "splunk.area",
      "dataSources": {
        "primary": "ds_leafs_14"
      },
      "title": "VXLAN Throughput per Leaf \u2014 TX+RX Bytes/min (Sub 40115)",
      "description": "Per-minute delta of the per-NVE uc/mc input+output byte counters (Sub 40115, periodic 1 min). Approximates VXLAN data-plane throughput on each leaf's NVE interface. One NVE (nve1) per device, so series are keyed by node only (the numeric unit-number list key is not carried as a telemetry dimension).",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VXLAN Bytes / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_leafs_15": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_15"
      },
      "title": "BUM vs Unicast TX Packets per Leaf \u2014 Packets/min (Sub 40115)",
      "description": "Per-minute delta of mc-output-packets (BUM/multicast) and uc-output-packets (unicast) from the NVE nve-oper-counters YANG path (Sub 40115). Each device produces two series: \"Leaf-XX (UC)\" and \"Leaf-XX (MC)\". In a healthy EVPN fabric with ARP suppression, UC dominates; a rising MC line indicates BUM flooding (unknown-unicast, ARP suppression miss, or control-plane gap). Note: mc-output-packets is not yet populated on CAT9KV virtual platforms \u2014 MC lines will be 0 in lab; counters are expected to be non-zero on physical Cat9K hardware.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "NVE TX Packets / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_leafs_16": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_16"
      },
      "title": "NVE Interface Packet Rate per Leaf \u2014 Packets/min over Time (Sub 40115)",
      "description": "Per-minute increment of the per-NVE unicast+multicast packet counters (uc-output + uc-input + mc-output, Sub 40115) charted over the selected time range, so each spike marks VXLAN packets crossing a leaf's NVE interface in that minute. Companion to the VXLAN Throughput (bytes/min) chart above. For a per-VNI top-talker breakout see the per-VNI throughput chart to the right (the numeric vni-id list key of nve-vni-oper-counters is now carried as a telemetry dimension).",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "NVE Packets / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_leafs_17": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_leafs_17"
      },
      "title": "Per-VNI VXLAN Throughput per Leaf \u2014 Top Talkers, Bytes/min (Sub 40115)",
      "description": "Per-minute delta of the per-VNI uc/mc input+output byte counters (nve-vni-oper-counters, Sub 40115), broken out by the numeric vni-id list key now carried as a telemetry dimension by the fixed yanggrpcreceiver. Each series is one VXLAN segment (hostname + VNI ID), revealing which VNIs are the top data-plane talkers on each leaf \u2014 a breakout that was previously impossible when numeric keys were dropped.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VXLAN Bytes / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_leafs_18": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_leafs_18"
      },
      "title": "Per-VNI Peer Reachability Matrix per Leaf \u2014 VNI \u00d7 Remote VTEP (1 = learned, 0 = gap)",
      "description": "Control-plane reachability of each VXLAN segment from the per-VNI / per-peer router-MAC table (nve-peer-oper/peer-vni-group), now sliceable because the fixed yanggrpcreceiver carries the numeric vni list key and the peer-addr key as dimensions. Each row is one leaf's VNI; each column is a remote VTEP (peer loopback resolved to a hostname); a cell = 1 when that leaf has learned the VNI's router-MAC from that peer, 0 when it has not. A 0 where a peer is expected to advertise the segment flags a missing/asymmetric EVPN binding \u2014 a per-segment cross-check that was impossible while numeric keys were dropped."
    },
    "viz_leafs_19": {
      "type": "splunk.sankey",
      "dataSources": {
        "primary": "ds_leafs_19"
      },
      "title": "NVE Peer Adjacency Flow: Hostname \u2192 Peer VTEP \u2192 VNI Mapping (Local \u2194 Remote)",
      "description": "Source: nve-oper/nve-peer-oper (= show nve peers) for the VTEP adjacency, joined to evpn-inst/evpn-vlan/evpn-peer for the per-peer local\u2194remote VNI mapping. Every NVE/VTEP peer each leaf has formed is keyed on the authoritative peer-addr (resolved to a hostname via the inventory loopback lookup). Where the peer has a learned EVPN VNI binding, the flow extends one more stage to \"VNI L:<local> R:<remote>\" \u2014 matching local/remote values confirm VNI consistency; a fork (L\u2260R) flags a VNI mismatch across the peering. Peers with no learned VNI binding simply end at the VTEP node. Replaces the former EVPN Peer VNI Mapping table.",
      "options": {
        "seriesColors": [
          "#1D6FA4",
          "#53A051",
          "#F8BE34",
          "#DC4E41",
          "#F1813F",
          "#6DB7C6"
        ]
      }
    },
    "viz_leafs_20": {
      "type": "splunk.sankey",
      "dataSources": {
        "primary": "ds_leafs_20"
      },
      "title": "EVPN VNI Binding \u2014 Control-Plane (EVPN) + Data-Plane (NVE) Cross-Check: Hostname \u2192 EVI (VRF) \u2192 L3 VNI \u2192 L2 VNI \u2192 Access VLAN (+ Core SVI)",
      "description": "Consolidated EVI/VNI binding view from evpn-inst/evpn-vlan, joined to nve-oper/nve-vni-oper to carry each L3 VNI's core SVI VLAN (replaces the former EVI/VNI Bindings and NVE VNI tables). Each path traces a leaf's EVPN instance (EVI = ni-name / VRF) down to its L3 VNI, L2 VNI, and access VLAN; each L3 VNI also branches to its programmed Core SVI VLAN from the NVE data-plane, so the full control-plane + data-plane binding hierarchy is visible in one flow.",
      "options": {
        "seriesColors": [
          "#1D6FA4",
          "#53A051",
          "#F8BE34",
          "#DC4E41",
          "#F1813F",
          "#6DB7C6"
        ]
      }
    }
  },
  "dataSources": {
    "ds_leafs_input0": {
      "type": "ds.search",
      "options": {
        "query": "| inputlookup evpn_device_inventory | stats count by site | fields site",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Site"
    },
    "ds_leafs_0": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-oper-state_info\") AS _m WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | sort 0 - _time | dedup hostname, \"vni-id\" | eval down=if(value=\"nve-vni-state-down\",1,0) | stats sum(down) AS Down count AS Total | eval Up=Total-Down | eval vni_state=\"\u25b2 \".Up.\"   \u25bc \".Down | fields vni_state",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "NVE VNIs \u25b2 Up / \u25bc Down (Leaves)"
    },
    "ds_leafs_1": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | stats count(eval(hold_time>0)) AS Up count(eval(hold_time==0)) AS Down | eval bgp_state=\"\u25b2 \".Up.\"   \u25bc \".Down | fields bgp_state",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "BGP Sessions \u25b2 Up / \u25bc Down (Leaves)"
    },
    "ds_leafs_2": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.cp-vnis.\") AS cp_vnis WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\", \"peer-addr\" | rename \"peer-addr\" AS peer_addr | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | stats dc(peer_addr) AS peers BY hostname | stats sum(peers) AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "VTEP Tunnel Peers (Leaves)"
    },
    "ds_leafs_3": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-type_info\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" AND value=\"nve-vni-type-l2\" | stats dc(\"vni-id\") AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Active L2 VNIs (Leaves)"
    },
    "ds_leafs_4": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-type_info\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" AND value=\"nve-vni-type-l3\" | stats dc(\"vni-id\") AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Active VRFs / L3 VNIs (Leaves)"
    },
    "ds_leafs_5": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS val WHERE `evpn_index` earliest=$timeRange.earliest$ BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | where _time < (now()-300) | stats count AS n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Silent Leaves (>5m)"
    },
    "ds_leafs_6": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ span=30s BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | eval established=if(hold_time>0, 1, 0) | stats sum(established) AS established by _time, hostname | xyseries _time hostname established | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP Established Sessions per Leaf"
    },
    "ds_leafs_7": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.l3cp-vni-num\") AS l3_vni_count WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | stats last(l3_vni_count) AS l3_vni_count by _time, hostname | xyseries _time hostname l3_vni_count | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "L3 VNI (VRF) Count per Leaf"
    },
    "ds_leafs_8": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.as\") AS remote_as latest(\"cisco.bgp-neighbor-counters.received.updates\") AS msg_rcvd latest(\"cisco.bgp-neighbor-counters.sent.updates\") AS msg_sent latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | rename \"vrf-name\" AS vrf_name, \"neighbor-id\" AS neighbor_id | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | lookup evpn_device_inventory loopback AS neighbor_id OUTPUT hostname AS peer_hostname | eval peer_hostname=coalesce(peer_hostname, neighbor_id) | eval vrf_name=lower(vrf_name) | stats max(hold_time) AS hold_time max(msg_rcvd) AS msg_rcvd max(msg_sent) AS msg_sent max(remote_as) AS remote_as values(ip_address) AS ip_address BY hostname, peer_hostname, vrf_name, neighbor_id | eval session_state=if(hold_time>0,\"ESTABLISHED\",\"DOWN\") | eval remote_as=tostring(round(remote_as,0)) | table hostname, ip_address, peer_hostname, remote_as, vrf_name, session_state, msg_rcvd, msg_sent | sort hostname, peer_hostname",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP EVPN Peering Detail"
    },
    "ds_leafs_9": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.connection.total-dropped\") AS drops WHERE `evpn_index` earliest=$timeRange.earliest$ span=auto \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | rename \"vrf-name\" AS vrf_name, \"neighbor-id\" AS neighbor_id | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | sort hostname vrf_name neighbor_id _time | streamstats window=1 current=false last(drops) AS _prev_drops BY hostname, vrf_name, neighbor_id | eval new_drops=drops-_prev_drops | eval new_drops=if(isnotnull(new_drops) AND new_drops>0, new_drops, 0) | stats sum(new_drops) AS new_drops by _time, hostname | xyseries _time hostname new_drops | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP Session Flaps \u2014 New Drops per Leaf Over Time"
    },
    "ds_leafs_10": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.bgp-neighbor-counters.received.updates\") AS upd_rcvd WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | rename \"vrf-name\" AS vrf_name, \"neighbor-id\" AS neighbor_id | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | sort hostname vrf_name neighbor_id _time | streamstats window=1 current=false last(upd_rcvd) AS _prev_upd BY hostname, vrf_name, neighbor_id | eval new_upd=upd_rcvd-_prev_upd | where isnotnull(new_upd) AND new_upd>=0 | stats sum(new_upd) AS update_rate by _time, hostname | xyseries _time hostname update_rate | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP Update Rate \u2014 Messages Received per Leaf"
    },
    "ds_leafs_11": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.bgp-table-version\") AS tbl_ver WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m BY \"cisco.node_id\", \"afi-safi\" | rename \"afi-safi\" AS afi_safi | where afi_safi=\"l2vpn-e-vpn\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | sort hostname _time | streamstats window=1 current=false last(tbl_ver) AS _prev_tbl_ver BY hostname | eval churn=tbl_ver-_prev_tbl_ver | where isnotnull(churn) AND churn>=0 | xyseries _time hostname churn | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP EVPN Table Version Churn \u2014 Route Changes/min per Leaf"
    },
    "ds_leafs_12": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.local-add.mac-cnt\") AS mac_l latest(\"cisco.remote-add.mac-cnt\") AS mac_r latest(\"cisco.local-add.mac-ip-cnt\") AS macip_l latest(\"cisco.remote-add.mac-ip-cnt\") AS macip_r WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-evpn-oper:evpn-oper-data/evpn-stats/evpn-vni-rt-cnt\" BY \"cisco.node_id\", \"vni\" | stats sum(mac_l) AS mac_l sum(mac_r) AS mac_r sum(macip_l) AS macip_l sum(macip_r) AS macip_r by _time, \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | eval total=mac_l+mac_r+macip_l+macip_r | sort hostname _time | streamstats window=1 current=false last(total) AS _prev BY hostname | eval churn=total-_prev | where isnotnull(churn) AND churn>=0 | stats sum(churn) AS churn by _time, hostname | xyseries _time hostname churn | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "MAC & MAC/IP Route Churn per Leaf (Sub 40113 \u2014 requires IOS-XE 26.2.1+)"
    },
    "ds_leafs_13": {
      "type": "ds.search",
      "options": {
        "query": "| mstats count(\"cisco.cp-vnis.\") AS cp_vnis WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\", \"peer-addr\" | rename \"peer-addr\" AS peer_addr | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | stats dc(peer_addr) AS nve_peers by _time, hostname | xyseries _time hostname nve_peers | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "NVE Peers Over Time \u2014 Per Leaf"
    },
    "ds_leafs_14": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.uc-output-bytes\") AS uc_out latest(\"cisco.mc-output-bytes\") AS mc_out latest(\"cisco.uc-input-bytes\") AS uc_in latest(\"cisco.mc-input-bytes\") AS mc_in WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper-counters\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | eval total=uc_out+mc_out+uc_in+mc_in | sort hostname _time | streamstats window=1 current=false last(total) AS _prev BY hostname | eval bytes_min=total-_prev | where isnotnull(bytes_min) AND bytes_min>=0 | xyseries _time hostname bytes_min | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "VXLAN Throughput per Leaf \u2014 TX+RX Bytes/min (Sub 40115)"
    },
    "ds_leafs_15": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.uc-output-packets\") AS uc_out latest(\"cisco.mc-output-packets\") AS mc_out WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper-counters\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | sort hostname _time | streamstats window=1 current=false last(uc_out) AS _puc last(mc_out) AS _pmc BY hostname | eval d_uc=uc_out-_puc, d_mc=mc_out-_pmc | where isnotnull(d_uc) AND d_uc>=0 AND d_mc>=0 | eval row=mvappend(_time.\"~UC~\".tostring(d_uc), _time.\"~MC~\".tostring(d_mc)) | mvexpand row | eval t=mvindex(split(row,\"~\"),0), type=mvindex(split(row,\"~\"),1), val=mvindex(split(row,\"~\"),2) | eval _time=tonumber(t), series=hostname.\" (\".type.\")\", pkts=tonumber(val) | stats sum(pkts) AS pkts BY _time, series | xyseries _time series pkts | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BUM vs Unicast TX Packets per Leaf \u2014 Packets/min (Sub 40115)"
    },
    "ds_leafs_16": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.uc-output-packets\") AS uc_tx latest(\"cisco.uc-input-packets\") AS uc_rx latest(\"cisco.mc-output-packets\") AS mc_tx WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper-counters\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | eval total=uc_tx+uc_rx+mc_tx | sort hostname _time | streamstats window=1 current=false last(total) AS _prev BY hostname | eval pkts_min=total-_prev | where isnotnull(pkts_min) AND pkts_min>=0 | stats sum(pkts_min) AS pkts_min BY _time, hostname | xyseries _time hostname pkts_min | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "NVE Interface Packet Rate per Leaf \u2014 Packets/min over Time (Sub 40115)"
    },
    "ds_leafs_17": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.uc-output-bytes\") AS uc_out latest(\"cisco.mc-output-bytes\") AS mc_out latest(\"cisco.uc-input-bytes\") AS uc_in latest(\"cisco.mc-input-bytes\") AS mc_in WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper-counters/nve-vni-oper-counters\" BY \"cisco.node_id\", \"vni-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | eval total=uc_out+mc_out+uc_in+mc_in, series=hostname.\" VNI \".'vni-id' | sort series _time | streamstats window=1 current=false last(total) AS _prev BY series | eval bytes_min=total-_prev | where isnotnull(bytes_min) AND bytes_min>=0 | xyseries _time series bytes_min | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "Per-VNI VXLAN Throughput per Leaf \u2014 Top Talkers, Bytes/min (Sub 40115)"
    },
    "ds_leafs_18": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.rmac_info\") AS present WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper/peer-vni-group\" BY \"cisco.node_id\", \"vni\", \"peer-addr\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | lookup evpn_device_inventory loopback AS \"peer-addr\" OUTPUT hostname AS peer_name | eval peer_name=coalesce(peer_name, 'peer-addr'), row=hostname.\" \u00b7 VNI \".'vni', present=1 | xyseries row peer_name present | fillnull value=0 | sort row",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Per-VNI Peer Reachability Matrix per Leaf \u2014 VNI \u00d7 Remote VTEP (1 = learned, 0 = gap)"
    },
    "ds_leafs_19": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.cp-vnis.\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\", \"peer-addr\" | rename \"peer-addr\" AS peer_addr, \"cisco.node_id\" AS node | eval has_adj=1 | append [ mstats latest(\"cisco.local-vni-id\") AS local_vni latest(\"cisco.remote-vni-id\") AS remote_vni WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-evpn-oper:evpn-oper-data/evpn-inst/evpn-vlan/evpn-peer\" BY \"cisco.node_id\", \"peer-ip-addr\" | rename \"peer-ip-addr\" AS peer_addr, \"cisco.node_id\" AS node ] | stats values(local_vni) AS local_vni values(remote_vni) AS remote_vni max(has_adj) AS has_adj BY node, peer_addr | where has_adj=1 | rename node AS \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | lookup evpn_device_inventory loopback AS peer_addr OUTPUT hostname AS peer_name | eval peer_name=coalesce(peer_name, peer_addr) | eval p1=hostname.\"|||\".\"VTEP \".peer_name | eval p2=if(isnotnull(local_vni), \"VTEP \".peer_name.\"|||\".\"VNI L:\".round(local_vni,0).\" R:\".round(remote_vni,0), null()) | eval pairs=mvappend(p1,p2) | mvexpand pairs | eval from=mvindex(split(pairs,\"|||\"),0), to=mvindex(split(pairs,\"|||\"),1) | stats count AS value BY from, to",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "NVE Peer Adjacency Flow: Hostname \u2192 Peer VTEP \u2192 VNI Mapping (Local \u2194 Remote)"
    },
    "ds_leafs_20": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.l2-vni\") AS l2_vni latest(\"cisco.l3-vni\") AS l3_vni WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-evpn-oper:evpn-oper-data/evpn-inst/evpn-vlan\" BY \"cisco.node_id\", \"evpn-inst-id\" | append [ mstats latest(\"cisco.ni-name_info\") AS _x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-evpn-oper:evpn-oper-data/evpn-inst/evpn-vlan\" BY \"cisco.node_id\", \"evpn-inst-id\", \"value\" | eval evi=value | fields \"cisco.node_id\", \"evpn-inst-id\", evi ] | stats values(l2_vni) AS l2_vni values(l3_vni) AS l3_vni values(evi) AS evi BY \"cisco.node_id\", \"evpn-inst-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"leaf\" | where l2_vni>0 | eval access_vlan='evpn-inst-id', jkey=hostname.\"::\".round(l3_vni,0) | join type=left jkey [ mstats latest(\"cisco.svi-vlan-id\") AS svi_vlan latest(\"cisco.l3-vni-id\") AS l3_vni_id WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\" | append [ mstats latest(\"cisco.vni-type_info\") AS _t WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | eval vni_type=value | fields \"cisco.node_id\", \"vni-id\", vni_type ] | stats values(svi_vlan) AS svi_vlan values(l3_vni_id) AS l3_vni_id values(vni_type) AS vni_type BY \"cisco.node_id\", \"vni-id\" | `evpn_lookup` | where role=\"leaf\" AND vni_type=\"nve-vni-type-l2\" AND svi_vlan>0 | eval jkey=hostname.\"::\".round(l3_vni_id,0) | stats max(svi_vlan) AS svi_vlan BY jkey ] | eval device=hostname, evi_label=\"EVI \".evi, l3_label=\"L3VNI \".round(l3_vni,0), l2_label=\"L2VNI \".round(l2_vni,0), vlan_label=\"VLAN \".round(access_vlan,0), svi_label=\"Core SVI \".round(svi_vlan,0) | eval pairs=mvappend(device.\"|||\".evi_label, evi_label.\"|||\".l3_label, l3_label.\"|||\".l2_label, l2_label.\"|||\".vlan_label, if(isnotnull(svi_vlan), l3_label.\"|||\".svi_label, null())) | mvexpand pairs | eval from=mvindex(split(pairs,\"|||\"),0), to=mvindex(split(pairs,\"|||\"),1) | stats count AS value BY from, to",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "EVPN VNI Binding \u2014 Control-Plane (EVPN) + Data-Plane (NVE) Cross-Check: Hostname \u2192 EVI (VRF) \u2192 L3 VNI \u2192 L2 VNI \u2192 Access VLAN (+ Core SVI)"
    }
  },
